// components/TopicList.jsx — Clean vertical list of topics (NO cards)
import React from "react";
import { Link } from "react-router-dom";
import { CATEGORIES } from "../data/topicsData";
import { getCompletedTopics } from "../utils/progress";

export default function TopicList({ topics }) {
  const completed = getCompletedTopics();

  if (topics.length === 0) {
    return (
      <p className="text-muted text-sm py-8">
        No topics match your search. Try a different keyword.
      </p>
    );
  }

  // Group topics by category
  const grouped = CATEGORIES.reduce((acc, cat) => {
    const items = topics.filter((t) => t.category === cat);
    if (items.length > 0) acc[cat] = items;
    return acc;
  }, {});

  return (
    <div className="space-y-8">
      {Object.entries(grouped).map(([category, items]) => (
        <div key={category}>
          {/* Category header */}
          <div className="flex items-center gap-3 mb-3">
            <span className="text-xs font-mono text-muted uppercase tracking-widest">
              {category}
            </span>
            <div className="flex-1 border-t border-border" />
          </div>

          {/* Topic list — vertical, no cards */}
          <ul className="space-y-0 list-none m-0 p-0">
            {items.map((topic) => {
              const isDone = completed.includes(topic.slug);
              return (
                <li key={topic.slug} className="border-b border-border last:border-0">
                  <Link
                    to={`/topic/${topic.slug}`}
                    className="flex items-center justify-between py-3 px-1 group no-underline"
                  >
                    <span className="text-gray-300 group-hover:text-white text-sm transition-colors">
                      {topic.name}
                    </span>
                    <div className="flex items-center gap-3">
                      {isDone && (
                        <span className="text-xs text-green-500 font-mono">✓ done</span>
                      )}
                      <span className="text-muted text-xs group-hover:text-accent transition-colors">
                        →
                      </span>
                    </div>
                  </Link>
                </li>
              );
            })}
          </ul>
        </div>
      ))}
    </div>
  );
}
